@impl(hir_stubs.identity)
def identity_impl(x: Var) -> Var:
    if x.is_constant():
        ty = x.get_type()
        if ty.is_aggregate():
            return make_aggregate(x.get_aggregate(), ty, x.get_loose_type())
        else:
            return loosely_typed_const(x.get_constant(), x.get_type(), x.get_loose_type())
    else:
        return x


